sql:
SELECT AVG(passenger_count) 
FROM airport_statistics 
WHERE iata_code = '1' AND year = 2023;

SELECT COUNT(service_name) 
FROM airport_services
WHERE iata_code = '1';

external_knowledge:
- "longest delays" refers to the maximum delay time for each departure airport;
- "details of the routes" include the route description, distance, and flight duration;
- "controllers and their experience" refers to the air traffic controllers working at the departure airports and their years of experience.

- "bustling with over 1000 passengers" refers to the `passenger_count` being greater than 1000;
- "priced at more than $500" refers to the `total_price` being greater than 500;
- "in June 2023" refers to the `month` and `year` being 6 and 2023, respectively;
- "delayed for more than 30 minutes" refers to the `total_delay_time` being greater than 30 minutes.

sql:
SELECT COUNT(DISTINCT airport_code) AS total_active_airports
FROM (
  SELECT departure_airport AS airport_code FROM flights
  UNION
  SELECT arrival_airport AS airport_code FROM flights
) AS active_airports;

